./code/rust-cuda/kernels/src/lib.rs<pre><code>use core::cmp::{max, min};
use core::mem::MaybeUninit;
use cuda_std::address_space;
use cuda_std::prelude::*;

pub const MAX_K: usize = 31;

#[kernel]
#[allow(improper_ctypes_definitions, clippy::missing_safety_doc)]
pub unsafe fn conv2d_gray_f32(
    input: &amp;[f32],
    output: *mut f32,
    weights: &amp;[f32],
    width: usize,
    height: usize,
    k_size: usize,
) {
    let x = (thread::block_idx_x() * thread::block_dim_x() + thread::thread_idx_x()) as usize;
    let y = (thread::block_idx_y() * thread::block_dim_y() + thread::thread_idx_y()) as usize;
    let lx = thread::thread_idx_x() as usize;
    let ly = thread::thread_idx_y() as usize;
    let bx = thread::block_dim_x() as usize;

    if x &lt; width &amp;&amp; y &lt; height {
        const MAX_K_2D: usize = MAX_K * MAX_K;

        #[address_space(shared)]
        static mut KLOCAL: [MaybeUninit&lt;f32&gt;; MAX_K_2D] = [MaybeUninit::uninit(); MAX_K_2D];

        let lid = ly * bx + lx;
        if lid &lt; k_size * k_size {
            unsafe {
                KLOCAL[lid].write(weights[lid]);
            }
        }

        thread::sync_threads();

        let r = (k_size - 1) / 2;
        let mut acc: f32 = 0.0;

        // Convolution sum
        for ky in 0..k_size {
            let mut iy = y + ky - r;
            iy = max(0usize, min(iy, height - 1));
            for kx in 0..k_size {
                let mut ix = x + kx - r;
                ix = max(0usize, min(ix, width - 1));
                let p = input[iy * width + ix];
                let w = unsafe { KLOCAL[ky * k_size + kx].assume_init() };
                acc += p * w;
            }
        }
        let o = unsafe { output.add(y * width + x) };
        unsafe { *o = acc };
    }
}
</code></pre> <p>Access data in the Rust kernel</p> <p><code>input</code> and <code>weights</code> are normal slices but the output  is a raw pointer. Since output is mutable state shared by multiple kernels executing in parallel.</p> <p>Using &amp;mut [T] would incorrectly indicate that it is non-shared mutable state, and therefore Rust CUDA does not allow mutable references as argument to kernels. Raw pointers do not have this restriction. Therefore, we use a pointer and only make a mutable reference once we have an element (c.add(i)) that we know won’t be touched by other kernel invocations.</p> <p>For more details, please have a look at https://rust-gpu.github.io/rust-cuda/guide/getting_started.html</p> ./code/rust-cuda/build.rs<pre><code>use std::env;
